advanced.InfoAsSlot:
// JavaScript
import "@maersk-global/mds-components-core/mc-avatar";

// HTML
<mc-avatar>
  <span slot="info">body text as HTML</span>
</mc-avatar>

advanced.CustomisedAppearance:
// JavaScript
import "@maersk-global/mds-components-core/mc-avatar";

// CSS
mc-avatar::part(avatar) {
  background-color: #00897A;
  color: #AAEAE0;
}
mc-avatar::part(tooltip-container) {
  background-color: #00897A;
  color: #AAEAE0;
  border-color: #00897A;
}
mc-avatar::part(tooltip-arrow) {
  background: #00897A;
  border-color: #00897A;
}

// HTML
<mc-avatar
  info="Jane Doe"
  initials="JAD"
>
</mc-avatar>

advanced.IllustrationWithCustomColors:
// JavaScript
import "@maersk-global/mds-components-core/mc-avatar";

// CSS
mc-avatar::part(avatar) {
  background-color: #87CDC6;
  padding: 2px;
}

// HTML
<mc-avatar
  imagesrc="/avatar.svg"
  fit="x-large"
  info="Illustration"
>
</mc-avatar>
